import { useState } from 'react';

const INITIAL_ITEMS = [
  { id: 1, name: 'Veg Seekh Kebab',  category: 'Starters',      price: 180, isVeg: true,  isAvailable: true,  emoji: '🥗', desc: 'Spiced cottage cheese & vegetables grilled in tandoor.' },
  { id: 2, name: 'Chicken Tikka',    category: 'Starters',      price: 280, isVeg: false, isAvailable: true,  emoji: '🍗', desc: 'Marinated chicken pieces grilled in tandoor.' },
  { id: 3, name: 'Paneer Tikka',     category: 'Starters',      price: 220, isVeg: true,  isAvailable: true,  emoji: '🧀', desc: 'Fresh cottage cheese marinated overnight in spices.' },
  { id: 4, name: 'Dal Makhani',      category: 'Main Course',   price: 160, isVeg: true,  isAvailable: true,  emoji: '🍲', desc: 'Slow cooked black lentils in butter and cream.' },
  { id: 5, name: 'Butter Chicken',   category: 'Main Course',   price: 280, isVeg: false, isAvailable: true,  emoji: '🍛', desc: 'Tender chicken in rich tomato butter gravy.' },
  { id: 6, name: 'Palak Paneer',     category: 'Main Course',   price: 200, isVeg: true,  isAvailable: false, emoji: '🥬', desc: 'Cottage cheese in smooth spiced spinach gravy.' },
  { id: 7, name: 'Garlic Naan',      category: 'Breads',        price: 40,  isVeg: true,  isAvailable: true,  emoji: '🫓', desc: 'Soft leavened bread with garlic butter.' },
  { id: 8, name: 'Veg Biryani',      category: 'Rice & Biryani', price: 180, isVeg: true,  isAvailable: true, emoji: '🍚', desc: 'Fragrant basmati rice with mixed vegetables.' },
  { id: 9, name: 'Masala Chai',      category: 'Beverages',     price: 40,  isVeg: true,  isAvailable: true,  emoji: '🫖', desc: 'Classic Indian spiced tea.' },
  { id: 10, name: 'Gulab Jamun',     category: 'Desserts',      price: 80,  isVeg: true,  isAvailable: true,  emoji: '🍮', desc: 'Soft milk dumplings in rose sugar syrup.' },
];

const CATEGORIES = ['Starters', 'Main Course', 'Breads', 'Rice & Biryani', 'Beverages', 'Desserts'];

const EMPTY_FORM = { name: '', category: 'Starters', price: '', emoji: '', isVeg: true, isAvailable: true, desc: '' };

export default function MenuManagement() {
  const [items, setItems]         = useState(INITIAL_ITEMS);
  const [activeCat, setActiveCat] = useState('All');
  const [search, setSearch]       = useState('');
  const [showModal, setShowModal] = useState(false);
  const [editItem, setEditItem]   = useState(null); // null = add new
  const [form, setForm]           = useState(EMPTY_FORM);
  const [deleteConfirm, setDeleteConfirm] = useState(null);
  const [saveMsg, setSaveMsg]     = useState('');

  const filtered = items.filter(item => {
    const matchCat    = activeCat === 'All' || item.category === activeCat;
    const matchSearch = item.name.toLowerCase().includes(search.toLowerCase());
    return matchCat && matchSearch;
  });

  const openAdd = () => {
    setEditItem(null);
    setForm(EMPTY_FORM);
    setShowModal(true);
  };

  const openEdit = (item) => {
    setEditItem(item);
    setForm({ ...item, price: item.price.toString() });
    setShowModal(true);
  };

  const handleFormChange = e => {
    const { name, value, type, checked } = e.target;
    setForm(prev => ({ ...prev, [name]: type === 'checkbox' ? checked : value }));
  };

  const handleSave = () => {
    if (!form.name || !form.price || !form.emoji) {
      setSaveMsg('Please fill in name, price and emoji.');
      return;
    }
    const item = { ...form, price: parseInt(form.price), id: editItem?.id || Date.now() };

    if (editItem) {
      setItems(prev => prev.map(i => i.id === editItem.id ? item : i));
    } else {
      setItems(prev => [...prev, item]);
    }
    setShowModal(false);
    setSaveMsg('');
  };

  const handleDelete = (id) => {
    setItems(prev => prev.filter(i => i.id !== id));
    setDeleteConfirm(null);
  };

  const toggleAvailability = (id) => {
    setItems(prev => prev.map(i => i.id === id ? { ...i, isAvailable: !i.isAvailable } : i));
  };

  return (
    <div className="flex flex-col gap-5">

      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-xl font-bold text-gray-900">Menu Management</h2>
          <p className="text-sm text-gray-500 mt-0.5">{items.length} items · {items.filter(i => i.isAvailable).length} available</p>
        </div>
        <button
          onClick={openAdd}
          className="bg-red-600 hover:bg-red-700 text-white text-sm font-semibold px-5 py-2.5 rounded-xl transition-colors flex items-center gap-2"
        >
          + Add Item
        </button>
      </div>

      {/* Search + filters */}
      <div className="flex items-center gap-3 flex-wrap">
        <input
          type="text"
          value={search}
          onChange={e => setSearch(e.target.value)}
          placeholder="Search menu items..."
          className="px-4 py-2.5 border border-gray-200 rounded-xl text-sm bg-white focus:outline-none focus:ring-2 focus:ring-red-500 w-64"
        />
        <div className="flex gap-2 flex-wrap">
          {['All', ...CATEGORIES].map(cat => (
            <button
              key={cat}
              onClick={() => setActiveCat(cat)}
              className={`px-3 py-1.5 rounded-lg text-xs font-medium border transition-colors ${
                activeCat === cat
                  ? 'bg-red-600 text-white border-red-600'
                  : 'bg-white text-gray-600 border-gray-200 hover:border-gray-300'
              }`}
            >
              {cat}
            </button>
          ))}
        </div>
      </div>

      {/* Menu items table */}
      <div className="bg-white border border-gray-200 rounded-2xl overflow-hidden">
        <table className="w-full text-sm">
          <thead>
            <tr className="bg-gray-50 border-b border-gray-100">
              <th className="text-left px-5 py-3 text-xs font-semibold text-gray-500 uppercase tracking-wider">Item</th>
              <th className="text-left px-5 py-3 text-xs font-semibold text-gray-500 uppercase tracking-wider">Category</th>
              <th className="text-left px-5 py-3 text-xs font-semibold text-gray-500 uppercase tracking-wider">Price</th>
              <th className="text-left px-5 py-3 text-xs font-semibold text-gray-500 uppercase tracking-wider">Type</th>
              <th className="text-left px-5 py-3 text-xs font-semibold text-gray-500 uppercase tracking-wider">Available</th>
              <th className="text-left px-5 py-3 text-xs font-semibold text-gray-500 uppercase tracking-wider">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-50">
            {filtered.map(item => (
              <tr key={item.id} className={`hover:bg-gray-50 transition-colors ${!item.isAvailable ? 'opacity-50' : ''}`}>
                <td className="px-5 py-3.5">
                  <div className="flex items-center gap-3">
                    <span className="text-2xl">{item.emoji}</span>
                    <div>
                      <p className="font-medium text-gray-900">{item.name}</p>
                      <p className="text-xs text-gray-400 max-w-[200px] truncate">{item.desc}</p>
                    </div>
                  </div>
                </td>
                <td className="px-5 py-3.5">
                  <span className="text-xs bg-gray-100 text-gray-600 px-2 py-1 rounded-lg font-medium">
                    {item.category}
                  </span>
                </td>
                <td className="px-5 py-3.5 font-bold text-red-600">₹{item.price}</td>
                <td className="px-5 py-3.5">
                  <div className={`veg-dot ${item.isVeg ? 'veg' : 'nonveg'}`} />
                </td>
                <td className="px-5 py-3.5">
                  <button
                    onClick={() => toggleAvailability(item.id)}
                    className={`relative inline-flex h-5 w-9 rounded-full transition-colors focus:outline-none ${
                      item.isAvailable ? 'bg-green-500' : 'bg-gray-300'
                    }`}
                  >
                    <span className={`inline-block w-4 h-4 bg-white rounded-full shadow transform transition-transform mt-0.5 ${
                      item.isAvailable ? 'translate-x-4' : 'translate-x-0.5'
                    }`} />
                  </button>
                </td>
                <td className="px-5 py-3.5">
                  <div className="flex gap-2">
                    <button
                      onClick={() => openEdit(item)}
                      className="text-xs text-blue-600 hover:text-blue-800 border border-blue-200 hover:border-blue-300 px-3 py-1.5 rounded-lg transition-colors font-medium"
                    >
                      Edit
                    </button>
                    <button
                      onClick={() => setDeleteConfirm(item.id)}
                      className="text-xs text-red-600 hover:text-red-800 border border-red-200 hover:border-red-300 px-3 py-1.5 rounded-lg transition-colors font-medium"
                    >
                      Delete
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>

        {filtered.length === 0 && (
          <div className="text-center py-12 text-gray-400">
            <div className="text-4xl mb-2">🍽️</div>
            <p>No items found</p>
          </div>
        )}
      </div>

      {/* ── ADD / EDIT MODAL ── */}
      {showModal && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-md shadow-xl">
            <div className="flex items-center justify-between px-6 py-4 border-b border-gray-100">
              <h3 className="font-bold text-gray-900 text-base">
                {editItem ? 'Edit Item' : 'Add New Item'}
              </h3>
              <button onClick={() => { setShowModal(false); setSaveMsg(''); }} className="text-gray-400 hover:text-gray-600 text-xl">×</button>
            </div>
            <div className="px-6 py-4 flex flex-col gap-4">

              {saveMsg && (
                <div className="bg-red-50 border border-red-200 text-red-600 text-sm px-3 py-2 rounded-lg">
                  {saveMsg}
                </div>
              )}

              <div className="grid grid-cols-4 gap-3">
                <div className="col-span-1">
                  <label className="block text-xs font-medium text-gray-500 mb-1.5">Emoji</label>
                  <input name="emoji" value={form.emoji} onChange={handleFormChange}
                    placeholder="🍛" maxLength={2}
                    className="w-full px-3 py-2.5 border border-gray-200 rounded-xl text-2xl text-center focus:outline-none focus:ring-2 focus:ring-red-500" />
                </div>
                <div className="col-span-3">
                  <label className="block text-xs font-medium text-gray-500 mb-1.5">Item name *</label>
                  <input name="name" value={form.name} onChange={handleFormChange}
                    placeholder="e.g. Paneer Tikka"
                    className="w-full px-3 py-2.5 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-red-500" />
                </div>
              </div>

              <div>
                <label className="block text-xs font-medium text-gray-500 mb-1.5">Description</label>
                <textarea name="desc" value={form.desc} onChange={handleFormChange}
                  rows={2} placeholder="Short description..."
                  className="w-full px-3 py-2.5 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-red-500 resize-none" />
              </div>

              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="block text-xs font-medium text-gray-500 mb-1.5">Category</label>
                  <select name="category" value={form.category} onChange={handleFormChange}
                    className="w-full px-3 py-2.5 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-red-500 bg-white">
                    {CATEGORIES.map(c => <option key={c}>{c}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-medium text-gray-500 mb-1.5">Price (₹) *</label>
                  <input name="price" value={form.price} onChange={handleFormChange}
                    type="number" placeholder="0"
                    className="w-full px-3 py-2.5 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-red-500" />
                </div>
              </div>

              <div className="flex gap-4">
                <label className="flex items-center gap-2 cursor-pointer">
                  <input type="checkbox" name="isVeg" checked={form.isVeg} onChange={handleFormChange} className="w-4 h-4 accent-green-600" />
                  <span className="text-sm font-medium text-gray-700 flex items-center gap-1">
                    <div className="veg-dot veg" /> Vegetarian
                  </span>
                </label>
                <label className="flex items-center gap-2 cursor-pointer">
                  <input type="checkbox" name="isAvailable" checked={form.isAvailable} onChange={handleFormChange} className="w-4 h-4 accent-green-600" />
                  <span className="text-sm font-medium text-gray-700">Available now</span>
                </label>
              </div>
            </div>
            <div className="flex gap-3 px-6 py-4 border-t border-gray-100">
              <button onClick={() => { setShowModal(false); setSaveMsg(''); }}
                className="flex-1 py-2.5 border border-gray-200 rounded-xl text-sm text-gray-600 hover:bg-gray-50 transition-colors">
                Cancel
              </button>
              <button onClick={handleSave}
                className="flex-1 py-2.5 bg-red-600 hover:bg-red-700 text-white rounded-xl text-sm font-semibold transition-colors">
                {editItem ? 'Save Changes' : 'Add Item'}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ── DELETE CONFIRM ── */}
      {deleteConfirm && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-sm p-6 shadow-xl text-center">
            <div className="text-4xl mb-3">🗑️</div>
            <h3 className="font-bold text-gray-900 mb-2">Delete item?</h3>
            <p className="text-sm text-gray-500 mb-5">This action cannot be undone.</p>
            <div className="flex gap-3">
              <button onClick={() => setDeleteConfirm(null)}
                className="flex-1 py-2.5 border border-gray-200 rounded-xl text-sm text-gray-600 hover:bg-gray-50">
                Cancel
              </button>
              <button onClick={() => handleDelete(deleteConfirm)}
                className="flex-1 py-2.5 bg-red-600 hover:bg-red-700 text-white rounded-xl text-sm font-semibold">
                Delete
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
